// Determine dormancy level and messaging strategy per contact
const contact = $input.item.json;
const days = parseFloat(contact.days_dormant) || 0;

let dormancyLevel, toneGuideline, ctaStrength, subjectHint;

if (days >= 14 && days <= 21) {
  dormancyLevel = 'warm';
  toneGuideline = 'Gentil check-in. Tom caloroso, curioso, sem pressão. Pergunta como o processo está a correr.';
  ctaStrength = 'soft';
  subjectHint = 'check-in amigável';
} else if (days >= 22 && days <= 30) {
  dormancyLevel = 'cooling';
  toneGuideline = 'Partilha conteúdo de valor: tendência de mercado, nova propriedade relevante ou insight de zona. Tom consultivo.';
  ctaStrength = 'medium';
  subjectHint = 'novidade de mercado';
} else {
  dormancyLevel = 'cold';
  toneGuideline = 'CTA forte mas elegante. Menciona escassez de boas oportunidades no mercado. Alerta de preço ou oportunidade exclusiva. Último toque antes de arquivar.';
  ctaStrength = 'strong';
  subjectHint = 'alerta exclusivo';
}

const language = contact.language_detected || 'pt';

const languageInstructions = {
  pt: 'Escreve em português europeu formal mas caloroso.',
  en: 'Write in natural British English, warm and professional.',
  fr: 'Écris en français formel mais chaleureux.',
  de: 'Schreibe auf Deutsch, formell aber herzlich.',
  ar: 'اكتب باللغة العربية الرسمية الدافئة.'
};

const langInstruction = languageInstructions[language] || languageInstructions.pt;

return [{
  json: {
    ...contact,
    dormancy_level: dormancyLevel,
    days_dormant_rounded: Math.round(days),
    tone_guideline: toneGuideline,
    cta_strength: ctaStrength,
    subject_hint: subjectHint,
    language_instruction: langInstruction
  }
}];

