// Parse Claude response and merge with contact data
const contact = $('Code — Dormancy Level').item.json;
const rawResponse = $input.item.json;

let claudeText = '';
try {
  claudeText = rawResponse.content?.[0]?.text || rawResponse.text || '{}';
} catch (e) {
  claudeText = '{}';
}

let messaging;
try {
  const cleaned = claudeText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  messaging = JSON.parse(cleaned);
} catch (e) {
  const firstName = contact.full_name?.split(' ')[0] || 'amigo/a';
  messaging = {
    whatsapp_message: `Olá ${firstName}, sou a Sofia da Agency Group. Queria saber se ainda procura propriedades na zona de ${contact.zone_interest || 'Lisboa'}. Temos novidades que podem interessar-lhe.`,
    email_subject: `Agency Group — novidade para ${firstName}`,
    email_body_html: `<p>Olá ${firstName},</p><p>Tenho estado a acompanhar o mercado e encontrei oportunidades interessantes que correspondem ao seu perfil. Posso partilhar?</p><p>Um abraço,<br>Sofia — Agency Group</p>`,
    internal_note: `Fallback message — Claude parse error. Dormancy: ${contact.dormancy_level}`
  };
}

return [{
  json: {
    ...contact,
    whatsapp_message: messaging.whatsapp_message,
    email_subject: messaging.email_subject,
    email_body_html: messaging.email_body_html,
    internal_note: messaging.internal_note
  }
}];

