// Aggregate results for Slack summary
const allItems = $input.all();
const reengaged = allItems.length;

const byLevel = { warm: 0, cooling: 0, cold: 0 };
allItems.forEach(item => {
  const level = item.json.dormancy_level || 'warm';
  if (byLevel[level] !== undefined) byLevel[level]++;
});

return [{
  json: {
    reengaged_total: reengaged,
    by_level: byLevel,
    messages_sent: reengaged * 2,
    executed_at: new Date().toISOString()
  }
}];

